const results = $input.item.json.results || [];
return results.map(place => ({
  json: {
    place_id: place.place_id,
    nome: place.name,
    endereco: place.formatted_address,
    status: place.business_status,
    rating: place.rating || null,
    total_avaliacoes: place.user_ratings_total || 0
  }
})).filter(r => r.json.status === 'OPERATIONAL');

const detail = $input.item.json.result || {};
const prev = $('Normalizar Resultados').item.json;

const telefone = detail.formatted_phone_number
  ? detail.formatted_phone_number.replace(/\D/g, '')
  : null;

if (!telefone) return [];

let whatsapp = telefone;
if (!whatsapp.startsWith('55')) whatsapp = '55' + whatsapp;
if (whatsapp.length === 12) whatsapp = whatsapp.slice(0,4) + '9' + whatsapp.slice(4);

return [{
  json: {
    id: `GILTEC-${Date.now()}-${Math.random().toString(36).substr(2,5).toUpperCase()}`,
    nome_empresa: prev.nome,
    endereco: detail.formatted_address || prev.endereco,
    telefone_raw: detail.formatted_phone_number,
    whatsapp,
    site: detail.website || '',
    rating: prev.rating,
    total_avaliacoes: prev.total_avaliacoes,
    status_crm: 'novo',
    primeiro_contato: false,
    data_captacao: new Date().toISOString(),
    follow_ups: []
  }
}];
